    13→/// Bootstrap is responsible for app initialization and configuration
    14→/// before the app is run.
    15→Future<void> bootstrap() async {
    16→  // Run everything in a zone to ensure consistent error handling
    17→  runZonedGuarded(() async {
    18→    // Initialize Flutter bindings first
    19→    WidgetsFlutterBinding.ensureInitialized();
    20→
    21→    // Track app start time
    22→    AppStartTracker.trackAppStart();
    23→
    24→    // Load environment variables with fallback
    25→    try {
    26→      await dotenv.load(fileName: '.env');
    27→    } catch (e) {
    28→      debugPrint('Warning: Failed to load .env file. Using default values.');
    29→      // Load example environment file as fallback
    30→      try {
    31→        await dotenv.load(fileName: '.env.example');
    32→      } catch (e) {
    33→        debugPrint(
    34→            'Warning: Failed to load .env.example file. Using hardcoded defaults.');
    35→      }
    36→    }
    37→
    38→    // Set preferred orientations
    39→    await SystemChrome.setPreferredOrientations([
    40→      DeviceOrientation.portraitUp,
    41→      DeviceOrientation.portraitDown,
    42→    ]);
    43→
    44→    // Initialize service locator first
    45→    await setupServiceLocator(isTest: false);
    46→
    47→    // Initialize error handling
    48→    ErrorHandler.initialize();
    49→
    50→    // Initialize SharedPreferences
    51→    final sharedPreferences = await SharedPreferences.getInstance();
    52→
    53→    // Create ProviderContainer for initialization
    54→    final container = ProviderContainer();
    55→
    56→    // Initialize TokenManager
    57→    await container.read(tokenManagerProvider.notifier).initialize();
    58→
    59→    // Run the app with proper provider initialization
    60→    runApp(
    61→      UncontrolledProviderScope(
    62→        container: container,
    63→        child: const App(),
    64→      ),
    65→    );
    66→  }, (error, stackTrace) {
    67→    // Report any errors not caught by the Flutter framework
    68→    ErrorHandler.reportError(
    69→      'Uncaught exception',
    70→      error,
    71→      stackTrace,
    72→    );
    73→  });
    74→}
