    31→/// JWT token claims and payload
    32→typedef JWTPayload = ({
    33→  String sub,
    34→  String iss,
    35→  int exp,
    36→  int iat,
    37→  String? email,
    38→  String? name,
    39→  List<String> groups,
    40→});
    41→
    42→/// Authentication metrics state
    43→typedef AuthMetricsState = ({
    44→  int failedAttempts,
    45→  DateTime? lastFailedAttempt,
    46→  bool isLocked,
    47→  Duration? lockoutRemaining,
    48→  List<String> recentErrors,
    49→  DateTime? lastSuccessfulLogin,
    50→  String? lastLoginIp,
    51→  String? lastLoginDevice,
    52→});
