    79→/// Group of authentication-related providers that manage the app's auth state
    80→/// and user information using AWS Cognito.
    81→///
    82→/// Usage:
    83→/// ```dart
    84→/// // Watch for auth state changes
    85→/// final authState = ref.watch(authStateProvider);
    86→///
    87→/// // Check if user is authenticated
    88→/// final isLoggedIn = ref.watch(isAuthenticatedProvider);
    89→///
    90→/// // Get current user
    91→/// final user = ref.watch(currentUserProvider);
    92→///
    93→/// // Access auth methods
    94→/// final auth = ref.read(authNotifierProvider.notifier);
    95→/// await auth.signIn(email, password);
    96→///
    97→/// // Check session status
    98→/// final isSessionValid = ref.watch(sessionStatusProvider);
    99→///
   100→/// // Monitor auth metrics
   101→/// final metrics = ref.watch(authMetricsProvider);
   102→/// ```
   103→
   104→/// Provider for the auth data source
   105→final authDataSourceProvider = Provider<AuthRemoteDataSource>((ref) {
   106→  return getIt<AuthRemoteDataSource>();
   107→});
   108→
   109→/// Provider for the auth repository
   110→final authRepositoryProvider =
   111→    Provider<AuthRepository>((ref) => getIt<AuthRepository>());
   112→
   113→/// Provider for the get current user use case
   114→final getCurrentUserProvider = Provider<GetCurrentUser>(
   115→    (ref) => GetCurrentUser(ref.watch(authRepositoryProvider)));
   116→
   117→/// Provider for the is signed in use case
   118→final isSignedInProvider = Provider<IsSignedIn>(
   119→    (ref) => IsSignedIn(ref.watch(authRepositoryProvider)));
   120→
   121→/// Provider for the login use case
   122→final loginProvider = Provider<LoginUseCase>(
   123→    (ref) => LoginUseCase(ref.watch(authRepositoryProvider)));
   124→
   125→/// Provider for the sign up use case
   126→final signUpProvider =
   127→    Provider<SignUp>((ref) => SignUp(ref.watch(authRepositoryProvider)));
   128→
   129→/// Provider for the sign out use case
   130→final signOutProvider =
   131→    Provider<SignOut>((ref) => SignOut(ref.watch(authRepositoryProvider)));
   132→
   133→/// Provider for the verify email use case
   134→final verifyEmailProvider = Provider<VerifyEmail>(
   135→    (ref) => VerifyEmail(ref.watch(authRepositoryProvider)));
   136→
   137→/// Provider for the resend verification email use case
   138→final resendVerificationEmailProvider =
   139→    Provider<resend.ResendVerificationEmail>(
   140→  (ref) => resend.ResendVerificationEmail(ref.watch(authRepositoryProvider)),
   141→);
   142→
   143→/// Provider for the forgot password use case
   144→final forgotPasswordProvider = Provider<ForgotPassword>(
   145→    (ref) => ForgotPassword(ref.watch(authRepositoryProvider)));
